Session fixation is a critical vulnerability where an attacker tricks a victim into using a session ID that the attacker already knows. If your application doesn't regenerate the session ID after successful authentication, the attacker can hijack the user's authenticated session.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');

const app = express();

app.use(session({
  secret: 'mysecret',
  resave: false,
  saveUninitialized: true // VULNERABLE: Creates session before auth
}));

app.use(express.json());

// VULNERABLE: No session regeneration after login
app.post('/login', async (req, res) => {
  const { username, password } = req.body;

  // Find user in database
  const user = await findUserByUsername(username);

  if (user && await bcrypt.compare(password, user.passwordHash)) {
    // VULNERABLE: Reusing the same session ID
    req.session.userId = user.id;
    req.session.username = user.username;
    req.session.isAuthenticated = true;

    res.json({ message: 'Login successful' });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```text
1. Attacker visits the site, receives session ID: abc123
2. Attacker crafts malicious link: https://target.com/login?SID=abc123
3. Attacker sends link to victim via phishing email
4. Victim clicks link, browser now uses session ID abc123
5. Victim logs in successfully
6. Attacker uses session ID abc123 to access victim's authenticated session

Alternatively via cookie injection:
Set-Cookie: connect.sid=s%3Aattacker-known-session-id
```

**Why This Is Dangerous**:
- Session ID remains the same before and after authentication, allowing session fixation attacks
- `saveUninitialized: true` creates sessions for unauthenticated users, making fixation easier
- Weak session secret makes session tokens predictable
- No session expiration or security flags configured

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');
const crypto = require('crypto');

const app = express();

app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false, // SECURE: Don't create sessions until needed
  name: '__Host-sessionId', // SECURE: Use __Host- prefix for additional protection
  cookie: {
    secure: process.env.NODE_ENV === 'production', // HTTPS only in production
    httpOnly: true, // Prevent JavaScript access
    sameSite: 'strict', // Prevent CSRF
    maxAge: 30 * 60 * 1000 // 30 minute timeout
  }
}));

app.use(express.json());

// SECURE: Regenerate session after successful login
app.post('/login', async (req, res) => {
  const { username, password } = req.body;

  const user = await findUserByUsername(username);

  if (user && await bcrypt.compare(password, user.passwordHash)) {
    // CRITICAL: Regenerate session ID to prevent fixation
    req.session.regenerate((err) => {
      if (err) {
        console.error('Session regeneration failed:', err);
        return res.status(500).json({ error: 'Authentication failed' });
      }

      req.session.userId = user.id;
      req.session.username = user.username;
      req.session.isAuthenticated = true;
      req.session.loginTime = Date.now();
      req.session.ipAddress = req.ip;

      res.json({ message: 'Login successful' });
    });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- `session.regenerate()`: Creates a new session ID after authentication, invalidating any previously known session ID
- `saveUninitialized: false`: Prevents session creation until authentication, reducing attack surface
- Secure cookie flags: `httpOnly`, `secure`, `sameSite` prevent session theft via XSS and CSRF
- Session metadata tracking: `loginTime` and `ipAddress` enable anomaly detection

Excellent question! Session regeneration should occur at ANY privilege level change, not just initial login. This includes role changes, password changes, and logout. Let me show you a production-ready pattern.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Redis client for session storage
const redisClient = createClient({
  url: process.env.REDIS_URL,
  socket: { tls: process.env.NODE_ENV === 'production' }
});
redisClient.connect().catch(console.error);

// Security headers
app.use(helmet());

// Rate limiting for auth endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Session configuration
app.use(session({
  store: new RedisStore({ client: redisClient }),
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  name: '__Host-sid',
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 30 * 60 * 1000,
    path: '/'
  },
  rolling: true // Reset expiration on activity
}));

app.use(express.json());

// Session regeneration utility with audit logging
async function regenerateSession(req, newData = {}) {
  return new Promise((resolve, reject) => {
    const oldSessionId = req.sessionID;
    const preservedData = { ...req.session };
    delete preservedData.cookie;

    req.session.regenerate((err) => {
      if (err) {
        console.error('[SECURITY] Session regeneration failed:', {
          oldSessionId: oldSessionId.substring(0, 8) + '...',
          error: err.message,
          ip: req.ip,
          timestamp: new Date().toISOString()
        });
        return reject(err);
      }

      // Restore necessary data and apply new data
      Object.assign(req.session, preservedData, newData, {
        regeneratedAt: Date.now(),
        previousSessionId: oldSessionId.substring(0, 8)
      });

      console.log('[AUDIT] Session regenerated:', {
        newSessionId: req.sessionID.substring(0, 8) + '...',
        reason: newData.regenerationReason || 'unknown',
        userId: req.session.userId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });

      resolve();
    });
  });
}

// Secure session destruction
async function destroySession(req) {
  return new Promise((resolve, reject) => {
    const sessionId = req.sessionID;
    const userId = req.session?.userId;

    req.session.destroy((err) => {
      if (err) {
        console.error('[SECURITY] Session destruction failed:', err);
        return reject(err);
      }

      console.log('[AUDIT] Session destroyed:', {
        sessionId: sessionId.substring(0, 8) + '...',
        userId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });

      resolve();
    });
  });
}

// Login with session regeneration
app.post('/login', authLimiter, async (req, res) => {
  try {
    const { username, password } = req.body;
    const user = await findUserByUsername(username);

    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      console.log('[SECURITY] Failed login attempt:', {
        username,
        ip: req.ip,
        userAgent: req.get('User-Agent'),
        timestamp: new Date().toISOString()
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    await regenerateSession(req, {
      userId: user.id,
      username: user.username,
      role: user.role,
      isAuthenticated: true,
      loginTime: Date.now(),
      ipAddress: req.ip,
      userAgent: req.get('User-Agent'),
      regenerationReason: 'login'
    });

    res.json({ message: 'Login successful', role: user.role });
  } catch (err) {
    console.error('[ERROR] Login failed:', err);
    res.status(500).json({ error: 'Authentication failed' });
  }
});

// Privilege escalation with session regeneration
app.post('/elevate-privileges', authLimiter, async (req, res) => {
  try {
    if (!req.session.isAuthenticated) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const { adminPassword } = req.body;
    const user = await findUserById(req.session.userId);

    // Verify admin credentials (second factor for elevation)
    if (!user.isAdmin || !(await bcrypt.compare(adminPassword, user.adminPasswordHash))) {
      console.log('[SECURITY] Failed privilege escalation:', {
        userId: req.session.userId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
      return res.status(403).json({ error: 'Elevation denied' });
    }

    // CRITICAL: Regenerate session on privilege change
    await regenerateSession(req, {
      role: 'admin',
      elevatedAt: Date.now(),
      regenerationReason: 'privilege_escalation'
    });

    res.json({ message: 'Privileges elevated to admin' });
  } catch (err) {
    console.error('[ERROR] Privilege escalation failed:', err);
    res.status(500).json({ error: 'Elevation failed' });
  }
});

// Secure logout
app.post('/logout', async (req, res) => {
  try {
    await destroySession(req);

    // Clear the session cookie
    res.clearCookie('__Host-sid', {
      path: '/',
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict'
    });

    res.json({ message: 'Logged out successfully' });
  } catch (err) {
    console.error('[ERROR] Logout failed:', err);
    // Still clear cookie even if session destruction fails
    res.clearCookie('__Host-sid');
    res.status(500).json({ error: 'Logout may be incomplete' });
  }
});

// Global logout - invalidate all sessions for user
app.post('/logout-all', async (req, res) => {
  try {
    if (!req.session.isAuthenticated) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const userId = req.session.userId;

    // Increment user's session version to invalidate all existing sessions
    await incrementUserSessionVersion(userId);

    await destroySession(req);
    res.clearCookie('__Host-sid');

    console.log('[AUDIT] Global logout executed:', {
      userId,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });

    res.json({ message: 'All sessions terminated' });
  } catch (err) {
    console.error('[ERROR] Global logout failed:', err);
    res.status(500).json({ error: 'Logout failed' });
  }
});

// Session validation middleware
const validateSession = async (req, res, next) => {
  if (!req.session.isAuthenticated) {
    return next();
  }

  // Check session version against user's current version
  const user = await findUserById(req.session.userId);
  if (!user || req.session.sessionVersion !== user.sessionVersion) {
    await destroySession(req);
    return res.status(401).json({ error: 'Session invalidated' });
  }

  // Check for IP address change (optional, can cause issues with mobile)
  if (req.session.ipAddress !== req.ip) {
    console.log('[SECURITY] IP address changed during session:', {
      userId: req.session.userId,
      originalIp: req.session.ipAddress,
      newIp: req.ip,
      timestamp: new Date().toISOString()
    });
    // Consider requiring re-authentication for sensitive operations
  }

  next();
};

app.use(validateSession);

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Session Regeneration at Every Privilege Change**:
```javascript
// Regenerate on: login, privilege escalation, role change, password change
await regenerateSession(req, { regenerationReason: 'password_change' });
```

2. **Server-Side Session Storage with Redis**:
```javascript
// Sessions stored server-side, not in cookies
store: new RedisStore({ client: redisClient })
// Enables global logout and session version tracking
```

3. **Session Version Tracking for Global Invalidation**:
```javascript
// Each user has a session version; incrementing invalidates all sessions
if (req.session.sessionVersion !== user.sessionVersion) {
  await destroySession(req);
}
```

**Additional Protections**:
- **Rate limiting on auth endpoints**: Prevents brute-force attacks on session fixation vectors
- **Comprehensive audit logging**: All session lifecycle events logged with IP, timestamp, and user context
- **Secure cookie attributes**: `__Host-` prefix, `httpOnly`, `secure`, `sameSite=strict` prevent session theft
- **IP address tracking**: Detects potential session hijacking from different networks
- **Session timeout with rolling expiration**: Balances security with usability
- **Graceful error handling**: Security failures don't leak information, sessions cleared on errors

Password reset functionality is one of the most commonly attacked features. Using a weak random number generator or predictable tokens can lead to complete account takeover, as seen in the 2023 Deezer breach affecting 229 million users.

**VULNERABLE CODE**:

```java
import java.sql.*;
import java.util.Random;
import javax.servlet.http.*;

public class PasswordResetController extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "app_user";
    private static final String DB_PASS = "app_password";

    // VULNERABLE: Using weak random number generator
    private Random random = new Random();

    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String email = request.getParameter("email");

        // VULNERABLE: No rate limiting on reset requests
        // VULNERABLE: Predictable token generation
        String resetToken = String.valueOf(random.nextInt(999999));

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // VULNERABLE: Token never expires
            String sql = "UPDATE users SET reset_token = ? WHERE email = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, resetToken);
            stmt.setString(2, email);
            stmt.executeUpdate();

            // VULNERABLE: Token sent in URL via HTTP (not HTTPS)
            String resetLink = "http://example.com/reset?token=" + resetToken;
            sendEmail(email, "Password Reset", "Click here: " + resetLink);

            // VULNERABLE: Confirms email exists in system
            response.getWriter().write("Reset link sent to " + email);
        } catch (Exception e) {
            // VULNERABLE: Leaks internal error details
            response.getWriter().write("Error: " + e.getMessage());
        }
    }

    private void sendEmail(String to, String subject, String body) {
        // Email sending implementation
    }
}
```

**Attack Payload**:
```bash
# Brute force predictable 6-digit tokens
for token in $(seq 000000 999999); do
    response=$(curl -s "http://example.com/reset?token=$token&newPassword=hacked123")
    if [[ $response != *"Invalid"* ]]; then
        echo "Valid token found: $token"
        break
    fi
done
```

**Why This Is Dangerous**:
- `java.util.Random` is not cryptographically secure and can be predicted
- 6-digit tokens have only 1 million possibilities - brute forceable in minutes
- No token expiration allows indefinite attack window
- No rate limiting enables automated enumeration
- HTTP transmission exposes tokens to network sniffing
- Response confirms valid email addresses (user enumeration)

**SECURE VERSION**:

```java
import java.security.SecureRandom;
import java.sql.*;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePasswordResetController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecurePasswordResetController.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "app_user";
    private static final String DB_PASS = "app_password";
    private static final int TOKEN_LENGTH = 32;
    private static final int TOKEN_EXPIRY_MINUTES = 15;

    // SECURE: Cryptographically secure random number generator
    private static final SecureRandom secureRandom = new SecureRandom();

    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String email = request.getParameter("email");

        // SECURE: Input validation
        if (email == null || !isValidEmail(email)) {
            logger.warn("Invalid email format in reset request from IP: {}", 
                       request.getRemoteAddr());
            sendGenericResponse(response);
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // SECURE: Generate cryptographically strong token
            byte[] tokenBytes = new byte[TOKEN_LENGTH];
            secureRandom.nextBytes(tokenBytes);
            String resetToken = Base64.getUrlEncoder().withoutPadding()
                                      .encodeToString(tokenBytes);

            // SECURE: Hash the token before storage
            String tokenHash = hashToken(resetToken);

            // SECURE: Set expiration time
            Timestamp expiresAt = Timestamp.from(
                Instant.now().plus(TOKEN_EXPIRY_MINUTES, ChronoUnit.MINUTES));

            // SECURE: Invalidate any existing tokens first
            invalidateExistingTokens(conn, email);

            String sql = "UPDATE users SET reset_token_hash = ?, " +
                        "reset_token_expires = ?, reset_attempts = 0 " +
                        "WHERE email = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, tokenHash);
            stmt.setTimestamp(2, expiresAt);
            stmt.setString(3, email);
            int updated = stmt.executeUpdate();

            if (updated > 0) {
                // SECURE: HTTPS only link
                String resetLink = "https://example.com/reset?token=" + resetToken;
                sendEmail(email, "Password Reset", buildSecureEmailBody(resetLink));
                logger.info("Password reset requested for user (email hash: {})", 
                           hashForLogging(email));
            }

            // SECURE: Always return same response (prevents user enumeration)
            sendGenericResponse(response);

        } catch (Exception e) {
            logger.error("Password reset error", e);
            sendGenericResponse(response);
        }
    }

    private void sendGenericResponse(HttpServletResponse response) {
        response.setContentType("application/json");
        response.getWriter().write(
            "{\"message\":\"If an account exists, a reset link will be sent.\"}");
    }

    private boolean isValidEmail(String email) {
        return email != null && email.matches("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$") 
               && email.length() <= 254;
    }

    private String hashToken(String token) {
        // Use SHA-256 for token hashing
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(token.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(hash);
    }
}
```

**Key Security Controls**:
- **SecureRandom**: Uses cryptographically secure PRNG instead of predictable Random
- **256-bit tokens**: Base64-encoded 32 bytes = ~43 characters, computationally infeasible to brute force
- **Token hashing**: Store only hashed tokens in database, preventing token theft from DB compromise
- **Short expiration**: 15-minute window limits attack opportunity
- **Generic responses**: Same response for valid/invalid emails prevents user enumeration

Excellent question! The token validation endpoint is equally critical. You need to implement multiple layers of defense including token verification, rate limiting, and secure password update procedures.

**PRODUCTION PATTERN**:

```java
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.sql.*;
import java.time.Instant;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.mindrot.jbcrypt.BCrypt;

public class SecurePasswordResetService {
    private static final Logger logger = LoggerFactory.getLogger(SecurePasswordResetService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private static final int MAX_RESET_ATTEMPTS = 3;
    private static final int RATE_LIMIT_WINDOW_SECONDS = 300;
    private static final int MAX_REQUESTS_PER_IP = 5;
    private static final int MIN_PASSWORD_LENGTH = 12;
    private static final int BCRYPT_ROUNDS = 12;

    // Rate limiting storage (use Redis in production)
    private final ConcurrentHashMap<String, RateLimitEntry> rateLimits = new ConcurrentHashMap<>();

    private final DataSource dataSource;
    private final PasswordPolicyValidator passwordValidator;
    private final NotificationService notificationService;

    public SecurePasswordResetService(DataSource dataSource) {
        this.dataSource = dataSource;
        this.passwordValidator = new PasswordPolicyValidator();
        this.notificationService = new NotificationService();
    }

    public ResetResult validateAndResetPassword(HttpServletRequest request,
                                                  String token,
                                                  String newPassword,
                                                  String confirmPassword) {
        String clientIp = getClientIp(request);
        String requestId = generateRequestId();

        // LAYER 1: Rate limiting by IP
        if (isRateLimited(clientIp)) {
            auditLogger.warn("[{}] Rate limit exceeded for IP: {}", requestId, clientIp);
            return ResetResult.rateLimited();
        }

        // LAYER 2: Input validation
        if (token == null || token.length() < 40 || token.length() > 50) {
            logger.warn("[{}] Invalid token format from IP: {}", requestId, clientIp);
            return ResetResult.invalidToken();
        }

        if (!newPassword.equals(confirmPassword)) {
            return ResetResult.passwordMismatch();
        }

        // LAYER 3: Password policy validation
        PasswordValidationResult policyResult = passwordValidator.validate(newPassword);
        if (!policyResult.isValid()) {
            return ResetResult.weakPassword(policyResult.getErrors());
        }

        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            try {
                // LAYER 4: Token verification with timing-safe comparison
                String tokenHash = hashToken(token);

                String sql = "SELECT id, email, reset_token_hash, reset_token_expires, " +
                            "reset_attempts, password_hash FROM users " +
                            "WHERE reset_token_hash IS NOT NULL FOR UPDATE";

                PreparedStatement stmt = conn.prepareStatement(sql);
                ResultSet rs = stmt.executeQuery();

                UserResetData userData = null;
                while (rs.next()) {
                    String storedHash = rs.getString("reset_token_hash");
                    // SECURE: Timing-safe comparison prevents timing attacks
                    if (MessageDigest.isEqual(
                            tokenHash.getBytes(StandardCharsets.UTF_8),
                            storedHash.getBytes(StandardCharsets.UTF_8))) {
                        userData = extractUserData(rs);
                        break;
                    }
                }

                if (userData == null) {
                    logger.warn("[{}] Invalid reset token from IP: {}", requestId, clientIp);
                    incrementRateLimit(clientIp);
                    return ResetResult.invalidToken();
                }

                // LAYER 5: Token expiration check
                if (Instant.now().isAfter(userData.tokenExpires)) {
                    auditLogger.info("[{}] Expired reset token for user: {}", 
                                    requestId, userData.userId);
                    invalidateToken(conn, userData.userId);
                    conn.commit();
                    return ResetResult.tokenExpired();
                }

                // LAYER 6: Attempt limiting per token
                if (userData.resetAttempts >= MAX_RESET_ATTEMPTS) {
                    auditLogger.warn("[{}] Max reset attempts exceeded for user: {}", 
                                    requestId, userData.userId);
                    invalidateToken(conn, userData.userId);
                    conn.commit();
                    return ResetResult.maxAttemptsExceeded();
                }

                // LAYER 7: Check password isn't same as current
                if (BCrypt.checkpw(newPassword, userData.currentPasswordHash)) {
                    return ResetResult.sameAsCurrent();
                }

                // LAYER 8: Check password history (prevent reuse)
                if (isPasswordInHistory(conn, userData.userId, newPassword)) {
                    return ResetResult.passwordReused();
                }

                // LAYER 9: Update password with strong hashing
                String newPasswordHash = BCrypt.hashpw(newPassword, 
                                                       BCrypt.gensalt(BCRYPT_ROUNDS));

                updatePasswordAndInvalidateToken(conn, userData.userId, newPasswordHash);
                addToPasswordHistory(conn, userData.userId, newPasswordHash);

                // LAYER 10: Invalidate all existing sessions
                invalidateAllSessions(conn, userData.userId);

                conn.commit();

                // LAYER 11: Notify user of password change
                notificationService.sendPasswordChangeNotification(
                    userData.email, clientIp, request.getHeader("User-Agent"));

                auditLogger.info("[{}] Password successfully reset for user: {} from IP: {}",
                               requestId, userData.userId, clientIp);

                return ResetResult.success();

            } catch (Exception e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            logger.error("[{}] Database error during password reset", requestId, e);
            return ResetResult.systemError();
        }
    }

    private void updatePasswordAndInvalidateToken(Connection conn, long userId, 
                                                   String passwordHash) throws SQLException {
        String sql = "UPDATE users SET password_hash = ?, reset_token_hash = NULL, " +
                    "reset_token_expires = NULL, reset_attempts = 0, " +
                    "password_changed_at = CURRENT_TIMESTAMP, " +
                    "failed_login_attempts = 0 WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, passwordHash);
        stmt.setLong(2, userId);
        stmt.executeUpdate();
    }

    private void invalidateAllSessions(Connection conn, long userId) throws SQLException {
        String sql = "DELETE FROM user_sessions WHERE user_id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        int invalidated = stmt.executeUpdate();
        logger.info("Invalidated {} sessions for user {}", invalidated, userId);
    }

    private boolean isPasswordInHistory(Connection conn, long userId, 
                                        String newPassword) throws SQLException {
        String sql = "SELECT password_hash FROM password_history " +
                    "WHERE user_id = ? ORDER BY created_at DESC LIMIT 10";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        ResultSet rs = stmt.executeQuery();

        while (rs.next()) {
            if (BCrypt.checkpw(newPassword, rs.getString("password_hash"))) {
                return true;
            }
        }
        return false;
    }

    private String hashToken(String token) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(token.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(hash);
    }

    private String getClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String generateRequestId() {
        byte[] bytes = new byte[8];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private static class RateLimitEntry {
        AtomicInteger count = new AtomicInteger(0);
        long windowStart = System.currentTimeMillis();
    }
}

public class PasswordPolicyValidator {
    private static final int MIN_LENGTH = 12;
    private static final int MAX_LENGTH = 128;

    public PasswordValidationResult validate(String password) {
        List<String> errors = new ArrayList<>();

        if (password == null || password.length() < MIN_LENGTH) {
            errors.add("Password must be at least " + MIN_LENGTH + " characters");
        }
        if (password != null && password.length() > MAX_LENGTH) {
            errors.add("Password must not exceed " + MAX_LENGTH + " characters");
        }
        if (!password.matches(".*[A-Z].*")) {
            errors.add("Password must contain at least one uppercase letter");
        }
        if (!password.matches(".*[a-z].*")) {
            errors.add("Password must contain at least one lowercase letter");
        }
        if (!password.matches(".*[0-9].*")) {
            errors.add("Password must contain at least one digit");
        }
        if (!password.matches(".*[!@#$%^&*()_+\\-=\\[\\]{}|;':,.<>?/].*")) {
            errors.add("Password must contain at least one special character");
        }
        // Check for common passwords
        if (isCommonPassword(password)) {
            errors.add("Password is too common. Please choose a stronger password");
        }

        return new PasswordValidationResult(errors.isEmpty(), errors);
    }

    private boolean isCommonPassword(String password) {
        // Check against top 10000 common passwords (load from file in production)
        Set<String> commonPasswords = loadCommonPasswords();
        return commonPasswords.contains(password.toLowerCase());
    }
}
