**Key Security Controls**:
- **Session regeneration**: Always create a new session ID after successful authentication
- **Old session invalidation**: Delete any pre-existing session before creating new one
- **Secure cookie attributes**: HttpOnly, Secure, SameSite=Strict prevent various attacks
- **Session binding**: Store IP and User-Agent to detect session theft

Absolutely! Session regeneration should occur at every privilege level change and before any sensitive operation. This defense-in-depth approach prevents session fixation at multiple stages and limits damage from compromised sessions.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"encoding/hex"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"sync"
	"time"
)

var (
	sessionStore = NewSecureSessionStore()
	logger       = slog.New(slog.NewJSONHandler(os.Stdout, nil))
)

type SecureSession struct {
	ID             string
	UserID         int
	Username       string
	Roles          []string
	PrivilegeLevel int
	CreatedAt      time.Time
	LastActivity   time.Time
	IPAddress      string
	UserAgent      string
	Fingerprint    string
	CSRFToken      string
}

type SecureSessionStore struct {
	mu       sync.RWMutex
	sessions map[string]*SecureSession
}

func NewSecureSessionStore() *SecureSessionStore {
	return &SecureSessionStore{
		sessions: make(map[string]*SecureSession),
	}
}

// SessionManager handles all session lifecycle events
type SessionManager struct {
	store           *SecureSessionStore
	maxAge          time.Duration
	idleTimeout     time.Duration
	regenerateAfter time.Duration
}

func NewSessionManager() *SessionManager {
	return &SessionManager{
		store:           sessionStore,
		maxAge:          24 * time.Hour,
		idleTimeout:     30 * time.Minute,
		regenerateAfter: 15 * time.Minute,
	}
}

// RegenerateSession creates new session ID, preserving session data
func (sm *SessionManager) RegenerateSession(w http.ResponseWriter, r *http.Request, reason string) (*SecureSession, error) {
	oldSession := sm.GetSession(r)
	if oldSession == nil {
		return nil, fmt.Errorf("no existing session")
	}

	// Generate new session ID
	newSessionID, err := generateCryptoSessionID()
	if err != nil {
		return nil, fmt.Errorf("failed to generate session ID: %w", err)
	}

	// Generate new CSRF token on regeneration
	newCSRFToken, err := generateCryptoSessionID()
	if err != nil {
		return nil, fmt.Errorf("failed to generate CSRF token: %w", err)
	}

	// Create new session with copied data
	newSession := &SecureSession{
		ID:             newSessionID,
		UserID:         oldSession.UserID,
		Username:       oldSession.Username,
		Roles:          oldSession.Roles,
		PrivilegeLevel: oldSession.PrivilegeLevel,
		CreatedAt:      time.Now(),
		LastActivity:   time.Now(),
		IPAddress:      r.RemoteAddr,
		UserAgent:      r.UserAgent(),
		Fingerprint:    generateFingerprint(r),
		CSRFToken:      newCSRFToken,
	}

	sm.store.mu.Lock()
	// Delete old session atomically with new session creation
	delete(sm.store.sessions, oldSession.ID)
	sm.store.sessions[newSessionID] = newSession
	sm.store.mu.Unlock()

	// Set new session cookie
	sm.setSessionCookie(w, newSessionID)

	// Audit log the regeneration
	logger.Info("session_regenerated",
		slog.String("reason", reason),
		slog.String("old_session_prefix", oldSession.ID[:8]),
		slog.String("new_session_prefix", newSessionID[:8]),
		slog.Int("user_id", newSession.UserID),
		slog.String("ip", r.RemoteAddr),
	)

	return newSession, nil
}

// ElevatePrivilege handles privilege escalation with mandatory session regeneration
func (sm *SessionManager) ElevatePrivilege(w http.ResponseWriter, r *http.Request, newRole string, newLevel int) error {
	// CRITICAL: Regenerate session before privilege change
	session, err := sm.RegenerateSession(w, r, "privilege_elevation")
	if err != nil {
		return fmt.Errorf("session regeneration failed: %w", err)
	}

	// Update privileges on the new session
	sm.store.mu.Lock()
	session.Roles = append(session.Roles, newRole)
	session.PrivilegeLevel = newLevel
	sm.store.mu.Unlock()

	logger.Info("privilege_elevated",
		slog.Int("user_id", session.UserID),
		slog.String("new_role", newRole),
		slog.Int("new_level", newLevel),
		slog.String("ip", r.RemoteAddr),
	)

	return nil
}

// ValidateSession performs comprehensive session validation
func (sm *SessionManager) ValidateSession(r *http.Request) (*SecureSession, error) {
	session := sm.GetSession(r)
	if session == nil {
		return nil, fmt.Errorf("session not found")
	}

	// Check absolute session timeout
	if time.Since(session.CreatedAt) > sm.maxAge {
		sm.DestroySession(session.ID)
		return nil, fmt.Errorf("session expired (max age)")
	}

	// Check idle timeout
	if time.Since(session.LastActivity) > sm.idleTimeout {
		sm.DestroySession(session.ID)
		return nil, fmt.Errorf("session expired (idle)")
	}

	// Validate session binding (detect session theft)
	currentFingerprint := generateFingerprint(r)
	if session.Fingerprint != currentFingerprint {
		logger.Warn("session_fingerprint_mismatch",
			slog.Int("user_id", session.UserID),
			slog.String("stored_fp", session.Fingerprint[:16]),
			slog.String("current_fp", currentFingerprint[:16]),
			slog.String("ip", r.RemoteAddr),
		)
		sm.DestroySession(session.ID)
		return nil, fmt.Errorf("session binding validation failed")
	}

	// Update last activity
	sm.store.mu.Lock()
	session.LastActivity = time.Now()
	sm.store.mu.Unlock()

	return session, nil
}

// RequireReauthentication for sensitive operations
func (sm *SessionManager) RequireReauthentication(w http.ResponseWriter, r *http.Request, verifyPassword func(string) bool) error {
	password := r.FormValue("current_password")

	if !verifyPassword(password) {
		logger.Warn("reauthentication_failed",
			slog.String("ip", r.RemoteAddr),
			slog.String("action", "sensitive_operation"),
		)
		return fmt.Errorf("reauthentication failed")
	}

	// Regenerate session after successful reauthentication
	_, err := sm.RegenerateSession(w, r, "reauthentication")
	if err != nil {
		return err
	}

	logger.Info("reauthentication_success",
		slog.String("ip", r.RemoteAddr),
		slog.String("action", "sensitive_operation"),
	)

	return nil
}

func (sm *SessionManager) GetSession(r *http.Request) *SecureSession {
	cookie, err := r.Cookie("session_id")
	if err != nil {
		return nil
	}

	sm.store.mu.RLock()
	session := sm.store.sessions[cookie.Value]
	sm.store.mu.RUnlock()

	return session
}

func (sm *SessionManager) DestroySession(sessionID string) {
	sm.store.mu.Lock()
	delete(sm.store.sessions, sessionID)
	sm.store.mu.Unlock()
}

func (sm *SessionManager) setSessionCookie(w http.ResponseWriter, sessionID string) {
	http.SetCookie(w, &http.Cookie{
		Name:     "session_id",
		Value:    sessionID,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   int(24 * time.Hour / time.Second),
	})
}

func generateCryptoSessionID() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return hex.EncodeToString(b), nil
}

func generateFingerprint(r *http.Request) string {
	data := r.UserAgent() + r.Header.Get("Accept-Language")
	hash := sha256.Sum256([]byte(data))
	return hex.EncodeToString(hash[:])
}

func getUserID(username string) int { return 1 }
func validateCredentials(username, password string) bool { return true }
```

