        // DEFENSE LAYER 1: Input sanitization
        $email = strtolower(trim($email));
        if (!filter_var($email, FILTER_VALIDATE_EMAIL)) {
            return $this->standardResponse();
        }

        // DEFENSE LAYER 2: IP-based rate limiting
        if ($this->isIpRateLimited($clientIp)) {
            $this->securityLogger->warning('IP rate limit exceeded for password reset', [
                'ip' => $clientIp,
                'email_hash' => hash('sha256', $email)
            ]);
            // Return standard response to prevent information leakage
            usleep(random_int(100000, 500000)); // Random delay 100-500ms
            return $this->standardResponse();
        }

        // DEFENSE LAYER 3: Email-based rate limiting
        if ($this->isEmailRateLimited($email)) {
            $this->securityLogger->warning('Email rate limit exceeded for password reset', [
                'email_hash' => hash('sha256', $email),
                'ip' => $clientIp
            ]);
            usleep(random_int(100000, 500000));
            return $this->standardResponse();
        }

        // DEFENSE LAYER 4: Check for suspicious patterns
        if ($this->detectSuspiciousActivity($clientIp, $email)) {
            $this->handleSuspiciousActivity($clientIp, $email);
            return $this->standardResponse();
        }

        // Increment rate limit counters
        $this->incrementRateLimitCounters($email, $clientIp);

        // Look up user (time-constant operation)
        $user = $this->findUserByEmail($email);

        // ANTI-ENUMERATION: Always take same time regardless of user existence
        $startTime = microtime(true);

        if ($user) {
            $this->processValidResetRequest($user, $clientIp);
        } else {
            // Simulate processing time for non-existent users
            usleep(random_int(50000, 150000));
            $this->logger->info('Reset requested for non-existent email', [
                'email_hash' => hash('sha256', $email)
            ]);
        }

        // Ensure consistent response time (200-400ms total)
        $elapsed = (microtime(true) - $startTime) * 1000000;
        $targetDelay = random_int(200000, 400000);
        if ($elapsed < $targetDelay) {
            usleep((int)($targetDelay - $elapsed));
        }

        return $this->standardResponse();
    }

    public function validateResetToken(string $token, string $newPassword, string $clientIp): array {
        // DEFENSE LAYER 1: Token format validation
        if (!$this->isValidTokenFormat($token)) {
            $this->securityLogger->warning('Invalid token format submitted', [
                'ip' => $clientIp
            ]);
            return ['success' => false, 'message' => 'Invalid or expired reset link'];
        }

        // DEFENSE LAYER 2: Rate limit token validation attempts
        if ($this->isTokenAttemptRateLimited($clientIp)) {
            $this->securityLogger->alert('Token brute force attempt detected', [
                'ip' => $clientIp
            ]);
            $this->lockoutIp($clientIp);
            return ['success' => false, 'message' => 'Too many attempts. Please try again later.'];
        }

        // DEFENSE LAYER 3: Password strength validation
        $passwordValidation = $this->validatePasswordStrength($newPassword);
        if (!$passwordValidation['valid']) {
            return ['success' => false, 'message' => $passwordValidation['message']];
        }

        // Increment token attempt counter
        $this->incrementTokenAttemptCounter($clientIp);

        // DEFENSE LAYER 4: Lookup token with timing-safe comparison
        $tokenHash = hash('sha256', $token);
        $resetRecord = $this->findValidResetToken($tokenHash);

        if (!$resetRecord) {
            $this->securityLogger->warning('Invalid token used', [
                'ip' => $clientIp,
                'token_prefix' => substr($token, 0, 8) . '...'
            ]);
            return ['success' => false, 'message' => 'Invalid or expired reset link'];
        }

        // DEFENSE LAYER 5: Check if token was recently used (replay attack)
        if ($this->isTokenRecentlyUsed($tokenHash)) {
            $this->securityLogger->alert('Token replay attack detected', [
                'ip' => $clientIp,
                'user_id' => $resetRecord['user_id']
            ]);
            return ['success' => false, 'message' => 'This reset link has already been used'];
        }

        // Process password reset in transaction
        return $this->executePasswordReset($resetRecord, $newPassword, $clientIp);
    }

    private function isIpRateLimited(string $ip): bool {
        $key = "password_reset:ip:{$ip}";
        $count = (int)$this->redis->get($key);
        return $count >= self::MAX_RESET_REQUESTS_PER_IP;
    }

    private function isEmailRateLimited(string $email): bool {
        $emailHash = hash('sha256', $email);
        $key = "password_reset:email:{$emailHash}";
        $count = (int)$this->redis->get($key);
        return $count >= self::MAX_RESET_REQUESTS_PER_EMAIL;
    }

    private function isTokenAttemptRateLimited(string $ip): bool {
        $key = "token_attempts:ip:{$ip}";
        $count = (int)$this->redis->get($key);
        return $count >= self::MAX_TOKEN_ATTEMPTS_PER_IP;
    }

    private function incrementRateLimitCounters(string $email, string $ip): void {
        $emailHash = hash('sha256', $email);

        $emailKey = "password_reset:email:{$emailHash}";
        $this->redis->incr($emailKey);
        $this->redis->expire($emailKey, 3600); // 1 hour

        $ipKey = "password_reset:ip:{$ip}";
        $this->redis->incr($ipKey);
        $this->redis->expire($ipKey, 3600); // 1 hour
    }

    private function incrementTokenAttemptCounter(string $ip): void {
        $key = "token_attempts:ip:{$ip}";
        $this->redis->incr($key);
        $this->redis->expire($key, 900); // 15 minutes
    }

    private function lockoutIp(string $ip): void {
        $key = "lockout:ip:{$ip}";
        $this->redis->setex($key, self::LOCKOUT_DURATION_MINUTES * 60, '1');

        $this->securityLogger->alert('IP locked out due to brute force', [
            'ip' => $ip,
            'duration_minutes' => self::LOCKOUT_DURATION_MINUTES
        ]);
    }

    private function detectSuspiciousActivity(string $ip, string $email): bool {
        // Check for lockout
        if ($this->redis->exists("lockout:ip:{$ip}")) {
            return true;
        }

        // Check for pattern: same IP requesting resets for multiple emails
        $emailsKey = "reset_emails:ip:{$ip}";
        $this->redis->sadd($emailsKey, hash('sha256', $email));
        $this->redis->expire($emailsKey, 3600);

        $uniqueEmails = $this->redis->scard($emailsKey);
        if ($uniqueEmails > 5) {
            return true;
        }

        return false;
    }

    private function handleSuspiciousActivity(string $ip, string $email): void {
        $this->lockoutIp($ip);
        $this->securityLogger->alert('Suspicious password reset activity detected', [
            'ip' => $ip,
            'email_hash' => hash('sha256', $email),
            'action' => 'IP locked out'
        ]);
    }

    private function findUserByEmail(string $email): ?array {
        $stmt = $this->pdo->prepare(
            "SELECT id, email, status FROM users WHERE email = ? AND status = 'active'"
        );
        $stmt->execute([$email]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    private function processValidResetRequest(array $user, string $clientIp): void {
        // Generate cryptographically secure token
        $token = bin2hex(random_bytes(self::TOKEN_LENGTH));
        $tokenHash = hash('sha256', $token);
        $expiresAt = date('Y-m-d H:i:s', strtotime('+' . self::TOKEN_EXPIRY_HOURS . ' hours'));

        // Invalidate existing tokens
        $deleteStmt = $this->pdo->prepare("DELETE FROM password_resets WHERE user_id = ?");
        $deleteStmt->execute([$user['id']]);

        // Store new token
        $insertStmt = $this->pdo->prepare(
            "INSERT INTO password_resets (user_id, token_hash, expires_at, created_ip, created_at) 
             VALUES (?, ?, ?, ?, NOW())"
        );
        $insertStmt->execute([$user['id'], $tokenHash, $expiresAt, $clientIp]);

        // Send email
        $this->sendResetEmail($user['email'], $token);

        $this->logger->info('Password reset token generated', [
            'user_id' => $user['id'],
            'ip' => $clientIp,
            'expires_at' => $expiresAt
        ]);
    }

    private function isValidTokenFormat(string $token): bool {
        return preg_match('/^[a-f0-9]{64}$/', $token) === 1;
    }

    private function findValidResetToken(string $tokenHash): ?array {
        $stmt = $this->pdo->prepare(
            "SELECT pr.id, pr.user_id, pr.expires_at, u.email 
             FROM password_resets pr 
             JOIN users u ON pr.user_id = u.id 
             WHERE pr.token_hash = ? AND pr.expires_at > NOW() AND pr.used_at IS NULL"
        );
        $stmt->execute([$tokenHash]);
        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    private function isTokenRecentlyUsed(string $tokenHash): bool {
        $key = "used_token:{$tokenHash}";
        return (bool)$this->redis->exists($key);
    }

    private function validatePasswordStrength(string $password): array {
        if (strlen($password) < self::MIN_PASSWORD_LENGTH) {
            return ['valid' => false, 'message' => 'Password must be at least 12 characters'];
        }

        if (!preg_match('/[A-Z]/', $password)) {
            return ['valid' => false, 'message' => 'Password must contain uppercase letter'];
        }

        if (!preg_match('/[a-z]/', $password)) {
            return ['valid' => false, 'message' => 'Password must contain lowercase letter'];
        }

        if (!preg_match('/[0-9]/', $password)) {
            return ['valid' => false, 'message' => 'Password must contain a number'];
        }

        // Check against common passwords (use HaveIBeenPwned API in production)
        $commonPasswords = ['Password123!', 'Welcome123!', 'Qwerty123!'];
        if (in_array($password, $commonPasswords)) {
            return ['valid' => false, 'message' => 'Password is too common'];
        }

        return ['valid' => true, 'message' => 'OK'];
    }

    private function executePasswordReset(array $resetRecord, string $newPassword, string $clientIp): array {
        $this->pdo->beginTransaction();

        try {
            // Update password with bcrypt
            $passwordHash = password_hash($newPassword, PASSWORD_BCRYPT, ['cost' => 12]);

            $updateStmt = $this->pdo->prepare(
                "UPDATE users SET password = ?, password_changed_at = NOW(), updated_at = NOW() WHERE id = ?"
            );
            $updateStmt->execute([$passwordHash, $resetRecord['user_id']]);

            // Mark token as used
            $tokenStmt = $this->pdo->prepare(
                "UPDATE password_resets SET used_at = NOW(), used_ip = ? WHERE id = ?"
            );
            $tokenStmt->execute([$clientIp, $resetRecord['id']]);

            // Invalidate all sessions
            $sessionStmt = $this->pdo->prepare("DELETE FROM user_sessions WHERE user_id = ?");
            $sessionStmt->execute([$resetRecord['user_id']]);

            // Cache used token hash to prevent replay
            $tokenHash = hash('sha256', $resetRecord['id']);
            $this->redis->setex("used_token:{$tokenHash}", 86400, '1');

            $this->pdo->commit();

            // Clear rate limit counters for this IP on success
            $this->redis->del("token_attempts:ip:{$clientIp}");

            $this->logger->info('Password successfully reset', [
                'user_id' => $resetRecord['user_id'],
                'ip' => $clientIp
            ]);

            // Send confirmation email
            $this->sendPasswordChangedEmail($resetRecord['email'], $clientIp);

            return ['success' => true, 'message' => 'Password successfully reset'];

        } catch (\Exception $e) {
            $this->pdo->rollBack();
            $this->logger->error('Password reset failed', [
                'user_id' => $resetRecord['user_id'],
                'error' => $e->getMessage()
            ]);
            return ['success' => false, 'message' => 'An error occurred. Please try again.'];
        }
    }

    private function standardResponse(): array {
        return [
            'success' => true,
            'message' => 'If an account exists with that email, a password reset link will be sent.'
        ];
    }

