**Additional Protections**:
- **Constant-time responses**: All requests take 200-400ms regardless of user existence
- **Pattern detection**: Automatically locks out IPs requesting resets for many different emails
- **Token replay prevention**: Used tokens cached in Redis, checked before processing
- **Session invalidation**: All active sessions terminated after password change
- **Confirmation emails**: User notified when password changes, including requesting IP
- **Separate security logging**: Security events logged separately for SIEM integration
- **Transaction integrity**: Database operations wrapped in transaction for consistency
- **Password strength enforcement**: Validates against common passwords and complexity rules

Session fixation is a serious vulnerability where an attacker can set or predict a user's session ID before authentication. After the victim logs in, the attacker uses the same session ID to hijack the authenticated session.

**VULNERABLE CODE**:

```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using System.Security.Claims;

namespace VulnerableApp.Controllers
{
    public class AuthController : Controller
    {
        private readonly IUserService _userService;

        public AuthController(IUserService userService)
        {
            _userService = userService;
        }

        [HttpPost("/login")]
        public IActionResult Login(string username, string password)
        {
            var user = _userService.ValidateCredentials(username, password);

            if (user != null)
            {
                // VULNERABLE: Session ID is NOT regenerated after authentication
                // The same session that existed before login continues to be used
                HttpContext.Session.SetString("UserId", user.Id.ToString());
                HttpContext.Session.SetString("Username", user.Username);
                HttpContext.Session.SetString("IsAuthenticated", "true");
                HttpContext.Session.SetString("Role", user.Role);

                return RedirectToAction("Dashboard", "Home");
            }

            return View("Login", new { Error = "Invalid credentials" });
        }

        [HttpGet("/logout")]
        public IActionResult Logout()
        {
            // VULNERABLE: Only clears session data, doesn't invalidate the session ID
            HttpContext.Session.Clear();
            return RedirectToAction("Login");
        }
    }
}
```

**Attack Scenario**:
```text
1. Attacker visits your site, gets session cookie: .AspNetCore.Session=abc123
2. Attacker sends victim link: https://yourapp.com/login?sid=abc123
   (or tricks victim's browser into accepting the session cookie)
3. Victim clicks link and logs in with their credentials
4. Server authenticates victim but keeps the SAME session ID (abc123)
5. Attacker uses cookie .AspNetCore.Session=abc123 to access victim's account
```

**Why This Is Dangerous**:
- The session ID remains unchanged after authentication, allowing pre-set sessions to gain elevated privileges
- Attackers can send malicious links with embedded session identifiers
- Even after logout, the session ID may still be valid if not properly invalidated
- Cross-site scripting can be combined to inject session cookies

**SECURE VERSION**:

```csharp
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Authentication;
using Microsoft.AspNetCore.Authentication.Cookies;
using System.Security.Claims;
using System.Threading.Tasks;

namespace SecureApp.Controllers
{
    public class AuthController : Controller
    {
        private readonly IUserService _userService;
        private readonly ILogger<AuthController> _logger;

        public AuthController(IUserService userService, ILogger<AuthController> logger)
        {
            _userService = userService;
            _logger = logger;
        }

        [HttpPost("/login")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> Login(string username, string password)
        {
            var user = _userService.ValidateCredentials(username, password);

            if (user != null)
            {
                // SECURE: Clear the existing session completely
                HttpContext.Session.Clear();
                await HttpContext.Session.CommitAsync();

                // SECURE: Create new claims-based identity (generates new session)
                var claims = new List<Claim>
                {
                    new Claim(ClaimTypes.NameIdentifier, user.Id.ToString()),
                    new Claim(ClaimTypes.Name, user.Username),
                    new Claim(ClaimTypes.Role, user.Role),
                    new Claim("LoginTime", DateTime.UtcNow.ToString("O"))
                };

                var claimsIdentity = new ClaimsIdentity(
                    claims, CookieAuthenticationDefaults.AuthenticationScheme);

                var authProperties = new AuthenticationProperties
                {
                    IsPersistent = false,
                    IssuedUtc = DateTimeOffset.UtcNow,
                    ExpiresUtc = DateTimeOffset.UtcNow.AddMinutes(30),
                    AllowRefresh = true
                };

                // SECURE: SignInAsync creates a NEW authentication cookie
                await HttpContext.SignInAsync(
                    CookieAuthenticationDefaults.AuthenticationScheme,
                    new ClaimsPrincipal(claimsIdentity),
                    authProperties);

                _logger.LogInformation(
                    "User {Username} logged in from {IP}",
                    user.Username, HttpContext.Connection.RemoteIpAddress);

                return RedirectToAction("Dashboard", "Home");
            }

            _logger.LogWarning(
                "Failed login attempt for {Username} from {IP}",
                username, HttpContext.Connection.RemoteIpAddress);

            return View("Login", new { Error = "Invalid credentials" });
        }

        [HttpPost("/logout")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> Logout()
        {
            var username = User.Identity?.Name;

            // SECURE: Completely invalidate the session
            HttpContext.Session.Clear();
            await HttpContext.Session.CommitAsync();

            // SECURE: Sign out destroys the authentication cookie
            await HttpContext.SignOutAsync(CookieAuthenticationDefaults.AuthenticationScheme);

            _logger.LogInformation("User {Username} logged out", username);

            return RedirectToAction("Login");
        }
    }
}
```

**Key Security Controls**:
- **Session regeneration**: `HttpContext.Session.Clear()` followed by `SignInAsync()` creates entirely new session credentials after authentication
- **Claims-based authentication**: Uses ASP.NET Core's built-in authentication which properly manages session lifecycle
- **Anti-forgery tokens**: `[ValidateAntiForgeryToken]` prevents CSRF attacks on login/logout
- **Secure cookie configuration**: Authentication properties control session expiration and refresh behavior
- **Audit logging**: All authentication events logged with IP addresses for forensics

