using Microsoft.AspNetCore.Authentication.Cookies;
using Microsoft.AspNetCore.DataProtection;
using Microsoft.AspNetCore.Http;
using System.Security.Claims;
using System.Security.Cryptography;

namespace SecureApp
{
    // Program.cs / Startup.cs configuration
    public static class SecurityConfiguration
    {
        public static void ConfigureSecureAuthentication(this IServiceCollection services)
        {
            // Data protection for encrypting cookies
            services.AddDataProtection()
                .PersistKeysToFileSystem(new DirectoryInfo(@"/var/keys"))
                .SetApplicationName("SecureApp")
                .SetDefaultKeyLifetime(TimeSpan.FromDays(90));

            services.AddAuthentication(CookieAuthenticationDefaults.AuthenticationScheme)
                .AddCookie(options =>
                {
                    // SECURE: Cookie configuration
                    options.Cookie.Name = "__Host-SecureApp-Auth";
                    options.Cookie.HttpOnly = true;
                    options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
                    options.Cookie.SameSite = SameSiteMode.Strict;
                    options.Cookie.IsEssential = true;

                    // SECURE: Session timeouts
                    options.ExpireTimeSpan = TimeSpan.FromMinutes(30);
                    options.SlidingExpiration = true;

                    // SECURE: Custom cookie validation
                    options.Events = new CookieAuthenticationEvents
                    {
                        OnValidatePrincipal = SecurityEvents.ValidateAsync,
                        OnSigningIn = SecurityEvents.OnSigningInAsync,
                        OnRedirectToLogin = context =>
                        {
                            context.Response.StatusCode = 401;
                            return Task.CompletedTask;
                        }
                    };

                    options.LoginPath = "/auth/login";
                    options.LogoutPath = "/auth/logout";
                    options.AccessDeniedPath = "/auth/forbidden";
                });

            // Session configuration
            services.AddSession(options =>
            {
                options.Cookie.Name = "__Host-SecureApp-Session";
                options.Cookie.HttpOnly = true;
                options.Cookie.SecurePolicy = CookieSecurePolicy.Always;
                options.Cookie.SameSite = SameSiteMode.Strict;
                options.IdleTimeout = TimeSpan.FromMinutes(20);
                options.IOTimeout = TimeSpan.FromSeconds(30);
            });

            services.AddSingleton<ISessionTokenService, SessionTokenService>();
        }
    }

    // Security event handlers
    public static class SecurityEvents
    {
        public static async Task ValidateAsync(CookieValidatePrincipalContext context)
        {
            var userService = context.HttpContext.RequestServices
                .GetRequiredService<IUserService>();
            var logger = context.HttpContext.RequestServices
                .GetRequiredService<ILogger<CookieAuthenticationEvents>>();

            var userId = context.Principal?.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            var sessionToken = context.Principal?.FindFirst("SessionToken")?.Value;
            var storedRole = context.Principal?.FindFirst(ClaimTypes.Role)?.Value;

            if (string.IsNullOrEmpty(userId) || string.IsNullOrEmpty(sessionToken))
            {
                context.RejectPrincipal();
                await context.HttpContext.SignOutAsync();
                return;
            }

            // SECURE: Validate session token against database
            var user = await userService.GetUserByIdAsync(int.Parse(userId));
            if (user == null || !await userService.ValidateSessionTokenAsync(userId, sessionToken))
            {
                logger.LogWarning(
                    "Invalid session token for user {UserId} from {IP}",
                    userId, context.HttpContext.Connection.RemoteIpAddress);
                context.RejectPrincipal();
                await context.HttpContext.SignOutAsync();
                return;
            }

            // SECURE: Check if user's role has changed (privilege escalation detection)
            if (user.Role != storedRole)
            {
                logger.LogWarning(
                    "Role mismatch detected for user {UserId}: stored={StoredRole}, current={CurrentRole}",
                    userId, storedRole, user.Role);
                context.RejectPrincipal();
                await context.HttpContext.SignOutAsync();
                return;
            }

            // SECURE: Check if user is still active
            if (!user.IsActive || user.IsLocked)
            {
                logger.LogWarning("Inactive/locked user {UserId} attempted access", userId);
                context.RejectPrincipal();
                await context.HttpContext.SignOutAsync();
                return;
            }
        }

        public static Task OnSigningInAsync(CookieSigningInContext context)
        {
            // SECURE: Add unique session token to prevent fixation
            var sessionToken = GenerateSecureToken();
            var identity = (ClaimsIdentity)context.Principal.Identity;
            identity.AddClaim(new Claim("SessionToken", sessionToken));
            identity.AddClaim(new Claim("SessionCreated", DateTime.UtcNow.ToString("O")));

            // Store token in database for validation
            var userService = context.HttpContext.RequestServices
                .GetRequiredService<IUserService>();
            var userId = context.Principal.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            _ = userService.StoreSessionTokenAsync(userId, sessionToken, 
                context.HttpContext.Connection.RemoteIpAddress?.ToString());

            return Task.CompletedTask;
        }

        private static string GenerateSecureToken()
        {
            var bytes = new byte[32];
            using var rng = RandomNumberGenerator.Create();
            rng.GetBytes(bytes);
            return Convert.ToBase64String(bytes);
        }
    }

